#include <string>
#include <stdexcept>

std::string solve(long long n) {
    // Function to convert a number to a given base (hex or base36)
    std::string convertToBase(long long num, int base) {
        std::string result;
        while (num > 0) {
            int remainder = static_cast<int>(num % base);
            if (remainder < 10) {
                result = std::to_string(remainder) + result;
            } else {
                char c = 'A' + (remainder - 10);
                result = std::string(1, c) + result;
            }
            num /= base;
        }
        return result;
    }

    // Calculate n^2 and n^3
    long long n2 = n * n;
    long long n3 = n2 * n;

    // Convert n^2 to hexadecimal (base 16)
    std::string hex = convertToBase(n2, 16);

    // Convert n^3 to base36 (digits 0-9 and letters A-Z)
    std::string base36 = convertToBase(n3, 36);

    // Concatenate the two results
    return hex + base36;
}
